   705→    public static void writeEndTransactionalMarker(ByteBuffer buffer, long initialOffset, long timestamp,
   706→                                                   int partitionLeaderEpoch, long producerId, short producerEpoch,
   707→                                                   EndTransactionMarker marker) {
   708→        boolean isTransactional = true;
   709→        try (MemoryRecordsBuilder builder = new MemoryRecordsBuilder(buffer, RecordBatch.CURRENT_MAGIC_VALUE, Compression.NONE,
   710→                TimestampType.CREATE_TIME, initialOffset, timestamp, producerId, producerEpoch,
   711→                RecordBatch.NO_SEQUENCE, isTransactional, true, partitionLeaderEpoch,
