   299→    private CloseableIterator<Record> uncompressedIterator() {
   300→        final ByteBuffer buffer = this.buffer.duplicate();
   301→        buffer.position(RECORDS_OFFSET);
   302→        return new RecordIterator() {
   303→            @Override
   304→            protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
   305→                try {
   306→                    return DefaultRecord.readFrom(buffer, baseOffset, baseTimestamp, baseSequence, logAppendTime);
   307→                } catch (BufferUnderflowException e) {
   308→                    throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached");
   309→                }
   310→            }
   311→            @Override
   312→            protected boolean ensureNoneRemaining() {
   313→                return !buffer.hasRemaining();
   314→            }
   315→            @Override
   316→            public void close() {}
   317→        };
   318→    }
   319→
   320→    @Override
   321→    public Iterator<Record> iterator() {
   322→        if (count() == 0)
   323→            return Collections.emptyIterator();
   324→
   325→        if (!isCompressed())
   326→            return uncompressedIterator();
   327→
   328→        // for a normal iterator, we cannot ensure that the underlying compression stream is closed,
   329→        // so we decompress the full record set here. Use cases which call for a lower memory footprint
   330→        // can use `streamingIterator` at the cost of additional complexity
   331→        try (CloseableIterator<Record> iterator = compressedIterator(BufferSupplier.NO_CACHING, false)) {
   332→            List<Record> records = new ArrayList<>(count());
   333→            while (iterator.hasNext())
   334→                records.add(iterator.next());
   335→            return records.iterator();
   336→        }
   337→    }
   338→
   339→    @Override
   340→    public CloseableIterator<Record> skipKeyValueIterator(BufferSupplier bufferSupplier) {
   341→        if (count() == 0) {
   342→            return CloseableIterator.wrap(Collections.emptyIterator());
   343→        }
   344→
   345→        /*
   346→         * For uncompressed iterator, it is actually not worth skipping key / value / headers at all since
   347→         * its ByteBufferInputStream's skip() function is less efficient compared with just reading it actually
   348→         * as it will allocate new byte array.
   349→         */
   350→        if (!isCompressed())
   351→            return uncompressedIterator();
   352→
   353→        // we define this to be a closable iterator so that caller (i.e. the log validator) needs to close it
   354→        // while we can save memory footprint of not decompressing the full record set ahead of time
   355→        return compressedIterator(bufferSupplier, true);
   356→    }
   357→
   358→    @Override
   359→    public CloseableIterator<Record> streamingIterator(BufferSupplier bufferSupplier) {
   360→        if (isCompressed())
   361→            return compressedIterator(bufferSupplier, false);
   362→        else
   363→            return uncompressedIterator();
   364→    }
