   408→    @Override
   409→    public boolean equals(Object o) {
   410→        if (this == o)
   411→            return true;
   412→        if (o == null || getClass() != o.getClass())
   413→            return false;
   414→
   415→        DefaultRecordBatch that = (DefaultRecordBatch) o;
   416→        return Objects.equals(buffer, that.buffer);
   417→    }
