   424→    private static byte computeAttributes(CompressionType type, TimestampType timestampType,
   425→                                          boolean isTransactional, boolean isControl, boolean isDeleteHorizonSet) {
   426→        if (timestampType == TimestampType.NO_TIMESTAMP_TYPE)
   427→            throw new IllegalArgumentException("Timestamp type must be provided to compute attributes for message " +
   428→                    "format v2 and above");
   429→
   430→        byte attributes = isTransactional ? TRANSACTIONAL_FLAG_MASK : 0;
   431→        if (isControl)
   432→            attributes |= CONTROL_FLAG_MASK;
   433→        if (type.id > 0)
   434→            attributes |= (byte) (COMPRESSION_CODEC_MASK & type.id);
   435→        if (timestampType == TimestampType.LOG_APPEND_TIME)
   436→            attributes |= TIMESTAMP_TYPE_MASK;
   437→        if (isDeleteHorizonSet)
   438→            attributes |= DELETE_HORIZON_FLAG_MASK;
   439→        return attributes;
   440→    }
