   624→    // visible for testing
   625→    abstract class StreamRecordIterator extends RecordIterator {
   626→        private final InputStream inputStream;
   627→
   628→        StreamRecordIterator(InputStream inputStream) {
   629→            super();
   630→            this.inputStream = inputStream;
   631→        }
   632→
   633→        abstract Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException;
   634→
   635→        @Override
   636→        protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
   637→            try {
   638→                return doReadRecord(baseOffset, baseTimestamp, baseSequence, logAppendTime);
   639→            } catch (IllegalArgumentException e) {
   640→                throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached", e);
   641→            } catch (IOException e) {
   642→                throw new KafkaException("Failed to decompress record stream", e);
   643→            }
   644→        }
   645→
   646→        @Override
   647→        protected boolean ensureNoneRemaining() {
   648→            try {
   649→                return inputStream.read() == -1;
