   454→        int offsetDelta = (int) (lastOffset - baseOffset);
   455→        writeHeader(buffer, baseOffset, offsetDelta, DefaultRecordBatch.RECORD_BATCH_OVERHEAD, magic,
   456→                    CompressionType.NONE, timestampType, RecordBatch.NO_TIMESTAMP, timestamp, producerId,
   457→                    producerEpoch, baseSequence, isTransactional, isControlRecord, false, partitionLeaderEpoch, 0);
   458→    }
   459→
   460→    public static void writeHeader(ByteBuffer buffer,
   461→                                   long baseOffset,
   462→                                   int lastOffsetDelta,
   463→                                   int sizeInBytes,
   464→                                   byte magic,
   465→                                   CompressionType compressionType,
   466→                                   TimestampType timestampType,
   467→                                   long baseTimestamp,
   468→                                   long maxTimestamp,
   469→                                   long producerId,
   470→                                   short epoch,
   471→                                   int sequence,
   472→                                   boolean isTransactional,
   473→                                   boolean isControlBatch,
   474→                                   boolean isDeleteHorizonSet,
   475→                                   int partitionLeaderEpoch,
   476→                                   int numRecords) {
   477→        if (magic < RecordBatch.CURRENT_MAGIC_VALUE)
   478→            throw new IllegalArgumentException("Invalid magic value " + magic);
   479→        if (baseTimestamp < 0 && baseTimestamp != NO_TIMESTAMP)
   480→            throw new IllegalArgumentException("Invalid message timestamp " + baseTimestamp);
   481→
   482→        short attributes = computeAttributes(compressionType, timestampType, isTransactional, isControlBatch, isDeleteHorizonSet);
   483→
   484→        int position = buffer.position();
   485→        buffer.putLong(position + BASE_OFFSET_OFFSET, baseOffset);
   486→        buffer.putInt(position + LENGTH_OFFSET, sizeInBytes - LOG_OVERHEAD);
   487→        buffer.putInt(position + PARTITION_LEADER_EPOCH_OFFSET, partitionLeaderEpoch);
   488→        buffer.put(position + MAGIC_OFFSET, magic);
   489→        buffer.putShort(position + ATTRIBUTES_OFFSET, attributes);
   490→        buffer.putLong(position + BASE_TIMESTAMP_OFFSET, baseTimestamp);
   491→        buffer.putLong(position + MAX_TIMESTAMP_OFFSET, maxTimestamp);
   492→        buffer.putInt(position + LAST_OFFSET_DELTA_OFFSET, lastOffsetDelta);
   493→        buffer.putLong(position + PRODUCER_ID_OFFSET, producerId);
   494→        buffer.putShort(position + PRODUCER_EPOCH_OFFSET, epoch);
   495→        buffer.putInt(position + BASE_SEQUENCE_OFFSET, sequence);
   496→        buffer.putInt(position + RECORDS_COUNT_OFFSET, numRecords);
   497→        long crc = Crc32C.compute(buffer, ATTRIBUTES_OFFSET, sizeInBytes - ATTRIBUTES_OFFSET);
   498→        buffer.putInt(position + CRC_OFFSET, (int) crc);
   499→        buffer.position(position + RECORD_BATCH_OVERHEAD);
   500→    }
   501→
   502→    @Override
   503→    public String toString() {
   504→        return "RecordBatch(magic=" + magic() + ", offsets=[" + baseOffset() + ", " + lastOffset() + "], " +
   505→                "sequence=[" + baseSequence() + ", " + lastSequence() + "], " +
   506→                "partitionLeaderEpoch=" + partitionLeaderEpoch() + ", " +
   507→                "isTransactional=" + isTransactional() + ", isControlBatch=" + isControlBatch() + ", " +
   508→                "compression=" + compressionType() + ", timestampType=" + timestampType() + ", crc=" + checksum() + ")";
   509→    }
   510→
   511→    public static int sizeInBytes(long baseOffset, Iterable<Record> records) {
   512→        Iterator<Record> iterator = records.iterator();
   513→        if (!iterator.hasNext())
   514→            return 0;
   515→
   516→        int size = RECORD_BATCH_OVERHEAD;
   517→        Long baseTimestamp = null;
   518→        while (iterator.hasNext()) {
   519→            Record record = iterator.next();
   520→            int offsetDelta = (int) (record.offset() - baseOffset);
   521→            if (baseTimestamp == null)
   522→                baseTimestamp = record.timestamp();
   523→            long timestampDelta = record.timestamp() - baseTimestamp;
   524→            size += DefaultRecord.sizeInBytes(offsetDelta, timestampDelta, record.key(), record.value(),
   525→                    record.headers());
   526→        }
   527→        return size;
   528→    }
   529→
   530→    public static int sizeInBytes(Iterable<SimpleRecord> records) {
   531→        Iterator<SimpleRecord> iterator = records.iterator();
   532→        if (!iterator.hasNext())
   533→            return 0;
   534→
   535→        int size = RECORD_BATCH_OVERHEAD;
   536→        int offsetDelta = 0;
   537→        Long baseTimestamp = null;
   538→        while (iterator.hasNext()) {
   539→            SimpleRecord record = iterator.next();
   540→            if (baseTimestamp == null)
   541→                baseTimestamp = record.timestamp();
   542→            long timestampDelta = record.timestamp() - baseTimestamp;
   543→            size += DefaultRecord.sizeInBytes(offsetDelta++, timestampDelta, record.key(), record.value(),
   544→                    record.headers());
   545→        }
   546→        return size;
   547→    }
   548→
   549→    /**
   550→     * Get an upper bound on the size of a batch with only a single record using a given key and value. This
   551→     * is only an estimate because it does not take into account additional overhead from the compression
   552→     * algorithm used.
   553→     */
   554→    static int estimateBatchSizeUpperBound(ByteBuffer key, ByteBuffer value, Header[] headers) {
   555→        return RECORD_BATCH_OVERHEAD + DefaultRecord.recordSizeUpperBound(key, value, headers);
   556→    }
   557→
   558→    public static int incrementSequence(int sequence, int increment) {
   559→        if (sequence > Integer.MAX_VALUE - increment)
   560→            return increment - (Integer.MAX_VALUE - sequence) - 1;
   561→        return sequence + increment;
   562→    }
   563→
   564→    public static int decrementSequence(int sequence, int decrement) {
   565→        if (sequence < decrement)
   566→            return Integer.MAX_VALUE - (decrement - sequence) + 1;
   567→        return sequence - decrement;
   568→    }
   569→
   570→    // visible for testing
   571→    abstract class RecordIterator implements CloseableIterator<Record> {
   572→        private final Long logAppendTime;
   573→        private final long baseOffset;
   574→        private final long baseTimestamp;
   575→        private final int baseSequence;
   576→        private final int numRecords;
   577→        private int readRecords = 0;
   578→
   579→        RecordIterator() {
   580→            this.logAppendTime = timestampType() == TimestampType.LOG_APPEND_TIME ? maxTimestamp() : null;
   581→            this.baseOffset = baseOffset();
   582→            this.baseTimestamp = baseTimestamp();
   583→            this.baseSequence = baseSequence();
   584→            int numRecords = count();
   585→            if (numRecords < 0)
   586→                throw new InvalidRecordException("Found invalid record count " + numRecords + " in magic v" +
   587→                        magic() + " batch");
   588→            this.numRecords = numRecords;
   589→        }
   590→
   591→        @Override
   592→        public boolean hasNext() {
   593→            return readRecords < numRecords;
   594→        }
   595→
   596→        @Override
   597→        public Record next() {
   598→            if (readRecords >= numRecords)
   599→                throw new NoSuchElementException();
   600→
   601→            readRecords++;
   602→            Record rec = readNext(baseOffset, baseTimestamp, baseSequence, logAppendTime);
   603→            if (readRecords == numRecords) {
   604→                // Validate that the actual size of the batch is equal to declared size
   605→                // by checking that after reading declared number of items, there no items left
   606→                // (overflow case, i.e. reading past buffer end is checked elsewhere).
   607→                if (!ensureNoneRemaining())
   608→                    throw new InvalidRecordException("Incorrect declared batch size, records still remaining in file");
   609→            }
   610→            return rec;
   611→        }
   612→
   613→        protected abstract Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime);
   614→
   615→        protected abstract boolean ensureNoneRemaining();
   616→
   617→        @Override
   618→        public void remove() {
   619→            throw new UnsupportedOperationException();
   620→        }
   621→
   622→    }
   623→
   624→    // visible for testing
   625→    abstract class StreamRecordIterator extends RecordIterator {
   626→        private final InputStream inputStream;
   627→
   628→        StreamRecordIterator(InputStream inputStream) {
   629→            super();
   630→            this.inputStream = inputStream;
   631→        }
   632→
   633→        abstract Record doReadRecord(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) throws IOException;
   634→
   635→        @Override
   636→        protected Record readNext(long baseOffset, long baseTimestamp, int baseSequence, Long logAppendTime) {
   637→            try {
   638→                return doReadRecord(baseOffset, baseTimestamp, baseSequence, logAppendTime);
   639→            } catch (IllegalArgumentException e) {
   640→                throw new InvalidRecordException("Incorrect declared batch size, premature EOF reached", e);
   641→            } catch (IOException e) {
   642→                throw new KafkaException("Failed to decompress record stream", e);
   643→            }
   644→        }
   645→
   646→        @Override
   647→        protected boolean ensureNoneRemaining() {
   648→            try {
   649→                return inputStream.read() == -1;
   650→            } catch (IOException e) {
   651→                throw new KafkaException("Error checking for remaining bytes after reading batch", e);
   652→            }
   653→        }
   654→
   655→        @Override
   656→        public void close() {
   657→            try {
   658→                inputStream.close();
   659→            } catch (IOException e) {
   660→                throw new KafkaException("Failed to close record stream", e);
   661→            }
   662→        }
   663→    }
   664→
   665→    static class DefaultFileChannelRecordBatch extends FileLogInputStream.FileChannelRecordBatch {
   666→
   667→        DefaultFileChannelRecordBatch(long offset,
   668→                                      byte magic,
   669→                                      FileRecords fileRecords,
   670→                                      int position,
   671→                                      int batchSize) {
   672→            super(offset, magic, fileRecords, position, batchSize);
   673→        }
   674→
   675→        @Override
   676→        protected RecordBatch toMemoryRecordBatch(ByteBuffer buffer) {
   677→            return new DefaultRecordBatch(buffer);
   678→        }
   679→
   680→        @Override
   681→        public long baseOffset() {
   682→            return offset;
   683→        }
   684→
   685→        @Override
   686→        public long lastOffset() {
   687→            return loadBatchHeader().lastOffset();
   688→        }
   689→
   690→        @Override
   691→        public long producerId() {
   692→            return loadBatchHeader().producerId();
   693→        }
   694→
   695→        @Override
   696→        public short producerEpoch() {
   697→            return loadBatchHeader().producerEpoch();
   698→        }
   699→
   700→        @Override
   701→        public int baseSequence() {
   702→            return loadBatchHeader().baseSequence();
   703→        }
   704→
   705→        @Override
   706→        public int lastSequence() {
   707→            return loadBatchHeader().lastSequence();
   708→        }
   709→
   710→        @Override
   711→        public Integer countOrNull() {
   712→            return loadBatchHeader().countOrNull();
   713→        }
   714→
   715→        @Override
   716→        public boolean isTransactional() {
   717→            return loadBatchHeader().isTransactional();
   718→        }
   719→
   720→        @Override
   721→        public OptionalLong deleteHorizonMs() {
   722→            return loadBatchHeader().deleteHorizonMs();
   723→        }
   724→
   725→        @Override
   726→        public boolean isControlBatch() {
   727→            return loadBatchHeader().isControlBatch();
   728→        }
   729→
   730→        @Override
   731→        public int partitionLeaderEpoch() {
   732→            return loadBatchHeader().partitionLeaderEpoch();
   733→        }
   734→
   735→        @Override
   736→        protected int headerSize() {
   737→            return RECORD_BATCH_OVERHEAD;
   738→        }
   739→    }
